// Get failed URLs from workflow static data, up to 10 per run
const staticData = $getWorkflowStaticData('global');
const failedQueue = staticData.failedQueue || [];

// Determine trigger source
const isWebhook = $('Webhook Trigger').isExecuted;
const triggerSource = isWebhook ? 'webhook' : 'schedule';

if (failedQueue.length === 0) {
  return [{ json: { empty: true, triggerSource, message: 'No failed URLs in queue' } }];
}

// Take up to 10 URLs for this run
const batch = failedQueue.slice(0, 10);

return [{
  json: {
    empty: false,
    triggerSource,
    urls: batch,
    totalInQueue: failedQueue.length,
    processingCount: batch.length
  }
}];

// Convert URLs array into individual items for SplitInBatches
const data = $input.first().json;
const urls = data.urls || [];

return urls.map(entry => ({
  json: {
    url: entry.url,
    retryCount: (entry.retryCount || 0),
    addedAt: entry.addedAt || new Date().toISOString(),
    triggerSource: data.triggerSource
  }
}));

// Process retry results and update the failed queue in static data
const staticData = $getWorkflowStaticData('global');
const failedQueue = staticData.failedQueue || [];
const allResults = $('Retry Ingest').all();
const batchItems = $('Prepare Batch').all();
const getData = $('Get Failed URLs').first().json;

const successUrls = new Set();
const stillFailed = [];
let successCount = 0;
let failCount = 0;

for (let i = 0; i < allResults.length; i++) {
  const result = allResults[i].json;
  const batchItem = batchItems[i] ? batchItems[i].json : {};
  const status = result.status || '';

  if (status === 'ingested' || result.success === true || status === 'duplicate') {
    successUrls.add(batchItem.url);
    successCount++;
  } else {
    failCount++;
    // Keep in queue with incremented retry count
    stillFailed.push({
      url: batchItem.url,
      retryCount: (batchItem.retryCount || 0) + 1,
      addedAt: batchItem.addedAt,
      lastError: result.message || result.error || 'Unknown error',
      lastRetry: new Date().toISOString()
    });
  }
}

// Remove successful URLs from the queue and merge remaining
const remainingQueue = failedQueue
  .filter(entry => !successUrls.has(entry.url))
  .map(entry => {
    // Update retry info for still-failed items
    const updated = stillFailed.find(f => f.url === entry.url);
    return updated || entry;
  });

// Cap at 100 entries, remove oldest first
if (remainingQueue.length > 100) {
  remainingQueue.splice(0, remainingQueue.length - 100);
}

staticData.failedQueue = remainingQueue;

return [{
  json: {
    success: true,
    triggerSource: getData.triggerSource,
    processed: allResults.length,
    succeeded: successCount,
    stillFailed: failCount,
    remainingInQueue: remainingQueue.length
  }
}];

// Helper: Add a URL to the failed queue (called externally or for manual additions)
// This node is a utility - it adds URLs to the static data failed queue
const staticData = $getWorkflowStaticData('global');
if (!staticData.failedQueue) {
  staticData.failedQueue = [];
}

const input = $input.first().json;
const url = input.url || '';
const error = input.error || 'Unknown error';

if (url) {
  // Check if URL already in queue
  const exists = staticData.failedQueue.some(entry => entry.url === url);
  if (!exists) {
    staticData.failedQueue.push({
      url: url,
      retryCount: 0,
      addedAt: new Date().toISOString(),
      lastError: error
    });

    // Cap at 100 entries
    if (staticData.failedQueue.length > 100) {
      staticData.failedQueue.splice(0, staticData.failedQueue.length - 100);
    }
  }
}

return [{ json: { queueSize: staticData.failedQueue.length } }];

// Merge node: simply pass through data from whichever trigger fired
// This allows both Schedule and Webhook triggers to feed into the same flow
const items = $input.all();
return items.length > 0 ? items : [{ json: { merged: true } }];
